/**
 * @summary Import historical event results (no per-criterion evaluation, score applied directly). Always previews (dryRun) unless dryRun=false and there are zero validation errors.
 */
export const ImportHistoricalResultsBody = zod.object({
  "csvData": zod.string().describe('CSV\/TSV with columns nome, nota, evento, data (header optional, auto-detected)'),
  "dryRun": zod.boolean().optional().describe('Defaults to true. Set to false to commit (only applied when there are zero errors).'),
  "linkOverrides": zod.record(zod.string(), zod.number()).optional().describe('Mapa opcional de groupKey (de HistoricalImportEventPlan) para o id de um evento existente ao qual esse grupo deve ser vinculado, em vez de criar um evento novo. Usado quando o admin identifica manualmente que um evento com action=create do preview é, na verdade, a mesma corrida de um dos overlapCandidates sugeridos (nome diferente do cadastrado manualmente).')
})

export const ImportHistoricalResultsResponse = zod.object({
  "success": zod.boolean(),
  "dryRun": zod.boolean(),
  "errors": zod.array(zod.string()),
  "totalRows": zod.number(),
  "matched": zod.number(),
  "unmatched": zod.array(zod.string()),
  "ambiguous": zod.array(zod.string()),
  "cycleFallback": zod.array(zod.string()).optional().describe('Eventos cuja data não cai em nenhum ciclo cadastrado e que serão vinculados ao ciclo atual automaticamente.'),
  "events": zod.array(zod.object({
  "eventName": zod.string(),
  "date": zod.string(),
  "score": zod.number().nullable(),
  "participantsCount": zod.number(),
  "matchedCount": zod.number(),
  "action": zod.enum(['create', 'update', 'conflict']),
  "existingEventId": zod.number().optional(),
  "cycleId": zod.number().optional(),
  "cycleName": zod.string().optional(),
  "cycleFallback": zod.boolean().optional().describe('true quando a data do evento não cai no período de nenhum ciclo cadastrado e o evento será vinculado ao ciclo atual como alternativa.'),
  "newEmployeeNames": zod.array(zod.string()).optional().describe('Nomes de colaboradores deste evento específico que serão cadastrados automaticamente.'),
  "groupKey": zod.string().describe('Identificador estável do grupo (evento normalizado + data), usado em linkOverrides.'),
  "overlapCandidates": zod.array(zod.object({
  "id": zod.number(),
  "name": zod.string(),
  "startDate": zod.string(),
  "endDate": zod.string(),
  "isHistorical": zod.boolean()
})).optional().describe('Apenas quando action=create. Eventos já cadastrados cujo período cobre esta data — possíveis duplicatas com nome diferente. Não bloqueiam a importação; o admin pode escolher vincular a um deles via linkOverrides em vez de criar um evento novo.')
})),
  "employeesToCreate": zod.array(zod.string()).optional().describe('Nomes de colaboradores não cadastrados que serão criados automaticamente ao confirmar.'),
  "employeesCreated": zod.number().optional().describe('Quantidade de colaboradores criados automaticamente (apenas no commit).'),
  "eventsCreated": zod.number().optional(),
  "eventsUpdated": zod.number().optional(),
  "participantsLinked": zod.number().optional(),
  "warnings": zod.array(zod.string()).optional()
})


/**
 * @summary Import the evaluator survey spreadsheet (one row = one evaluator's answer for one event). Creates avaliador users (deduped by name), never auto-creates events (every spreadsheet event must be linked to an existing event via linkOverrides), converts numeric 0-10 answers into real per-criterion evaluations for non-historical events, turns the four Sim/Não questions into event_conformities (worst case wins), and stores historical-event comments as importedNotes only. Also runs the criteria catalog migration (activate "Carga na Saída do Galpão", deactivate 3 retired criteria) inside the commit transaction. Always previews (dryRun) unless dryRun=false and there are zero validation errors and every group is linked.
 */
export const ImportSurveyBody = zod.object({
  "rows": zod.array(zod.array(zod.unknown())).describe('Linhas da planilha (sem cabeçalho), cada uma um array de 29 células na ordem original das colunas do xlsx.'),
  "dryRun": zod.boolean().optional().describe('Defaults to true. Set to false to commit (only applied when there are zero errors and every group is linked).'),
  "linkOverrides": zod.record(zod.string(), zod.number()).optional().describe('Mapa de groupKey (de SurveyGroupPlan) para o id do evento já cadastrado ao qual esse grupo da planilha deve ser vinculado. Use -1 para IGNORAR o grupo (linhas não são importadas). Obrigatório para todos os grupos antes do commit — este import nunca cria eventos novos.')
})

export const ImportSurveyResponse = zod.object({
  "success": zod.boolean(),
  "dryRun": zod.boolean(),
  "errors": zod.array(zod.string()),
  "totalRows": zod.number(),
  "groups": zod.array(zod.object({
  "groupKey": zod.string().describe('Identificador estável do grupo (texto do evento normalizado), usado em linkOverrides.'),
  "eventLabel": zod.string().describe('Texto original da coluna Evento+cidade+data da planilha.'),
  "rowCount": zod.number(),
  "distinctEvaluators": zod.number(),
  "linkedEventId": zod.number().optional(),
  "linkedEvent": zod.object({
  "id": zod.number(),
  "name": zod.string(),
  "startDate": zod.string(),
  "isHistorical": zod.boolean(),
  "status": zod.string(),
  "cycleId": zod.number()
}).optional(),
  "suggestions": zod.array(zod.object({
  "id": zod.number(),
  "name": zod.string(),
  "startDate": zod.string(),
  "isHistorical": zod.boolean()
})).describe('Eventos já cadastrados sugeridos por semelhança de nome\/cidade, para ajudar a escolher o vínculo.'),
  "resolved": zod.boolean().describe('true quando um linkOverride válido (evento ou -1\/ignorar) foi informado para este grupo.'),
  "ignored": zod.boolean().optional().describe('true quando o grupo foi marcado para ser ignorado (linkOverride -1).')
})),
  "unresolvedGroups": zod.array(zod.string()).describe('groupKeys ainda sem vínculo — precisam de linkOverrides antes do commit.'),
  "avaliadoresToCreate": zod.array(zod.string()).describe('Nomes de avaliadores que serão criados como usuários novos ao confirmar.'),
  "catalogChanges": zod.object({
  "toDeactivate": zod.array(zod.string()).describe('Nomes de critérios que serão desativados (active=false) no commit.'),
  "toCreateOrActivate": zod.array(zod.string()).describe('Nomes de critérios que serão criados ou reativados no commit.')
}),
  "warnings": zod.array(zod.string()),
  "duplicateRowsIgnored": zod.number().optional().describe('Respostas repetidas do mesmo avaliador para o mesmo evento — só a mais recente é importada.'),
  "evaluationsAlreadyInApp": zod.number().optional().describe('Notas da planilha que já existem no app (mesmo evento, quesito e avaliador) e serão puladas.'),
  "usersCreated": zod.number().optional(),
  "evaluationsCreated": zod.number().optional(),
  "evaluationsSkipped": zod.number().optional().describe('Notas puladas no commit por já existirem no app (mesmo evento, quesito e avaliador).'),
  "assignmentsCreated": zod.number().optional(),
  "conformitiesUpserted": zod.number().optional(),
  "eventsUpdated": zod.number().optional(),
  "createdAvaliadores": zod.array(zod.object({
  "name": zod.string(),
  "email": zod.string(),
  "tempPassword": zod.string().describe('Senha provisória em texto puro, retornada apenas uma vez neste response para o RH distribuir ao avaliador.')
})).optional().describe('Apenas no commit — credenciais provisórias dos avaliadores criados.')
})


/**
 * @summary Remove duplicate evaluations: exact copies (same event, criterion, evaluator, score and comment) keeping the first recorded one. Duplicates with different content are never touched. Recomputes affected cycle results after cleanup. Runs as preview (dryRun) unless dryRun=false.
 */
export const DedupeEvaluationsBody = zod.object({
  "dryRun": zod.boolean().optional().describe('Quando true (padrão), apenas conta as duplicatas sem apagar nada.')
})

